import javax.xml.parsers.*; // For SAXParser, InputSource etc
import org.xml.sax.*;   //For XMLReader and DocumentBuilderFactory interfaces   
public class java_48352_XMLParser_A08 {    
       public static void main(String[] args) throws ParserConfigurationException{       
            try { 
                String xmlFile = "sample-file.xml";     
                 SAXParser saxParser=SAXParserFactory.newInstance().createSAXParser();   // Parse XML using SAX   
                  MyHandler myhandler = new MyHandler();     // Handler to handle each element in the document 
                   saxParser.parse(xmlFile,myhandler);      // Parsing begins from here      
            } catch (Exception e) {        
                System.out.println("Error parsing XML file");         
                  e.printStackTrace();   
             }  
        } 
}    
